/**
 * PSO Blue Burst class data (character-progression spec).
 *
 * GENERATED from newserv's system/tables/level-table-v4.json — do not hand-edit
 * stat values; see docs/newserv-reference.md. Unit conventions preserved from
 * the original table:
 * - The table holds RAW PlyLevelTbl values; the BB client applies a further
 *   per-class transform before stats are displayed or used (role ATP bonus,
 *   HP multiplier, per-class ATA constant, derived TP). The authored transform
 *   constants live below (ROLE_ATP_BONUS / ROLE_HP_MULT_HUNDREDTHS /
 *   CLASS_ATA_CONST_TENTHS); progression.statsAtLevel applies them.
 * - Raw values: level 1 is `base` verbatim; reaching level L adds
 *   `deltas.*[L-2]`.
 * - ATA: `base.ata`, the deltas, and `max.ataTenths` are ALL in TENTHS of a
 *   display point (HUmar base 30 = 3.0 display; the client's class constant,
 *   e.g. 650, brings level 1 to the familiar 68.0).
 * - `xpThresholds[L-1]` is the cumulative XP required to be level L
 *   (thresholds[0] = 0); level cap is 200.
 * - LCK never grows from leveling (authentic BB behavior).
 */

export type ClassRole = "hunter" | "ranger" | "force";

export interface ClassGrowth {
  atp: number[];
  dfp: number[];
  ataTenths: number[];
  evp: number[];
  mst: number[];
  hp: number[];
}

export interface ClassDef {
  id: string;
  name: string;
  role: ClassRole;
  /** Profession ATP variance (Pvar) — authored per-role balance value. */
  pvar: number;
  base: { atp: number; dfp: number; ata: number; evp: number; lck: number; mst: number; hp: number };
  max: { atp: number; dfp: number; ataTenths: number; evp: number; mst: number; hp: number };
  /** Per-level gains; index L-2 is applied when reaching level L (length 199). */
  deltas: ClassGrowth;
  /** Cumulative XP required for each level; index L-1 = level L (length 200). */
  xpThresholds: number[];
}

export const LEVEL_CAP = 200;

export const SECTION_IDS = [
  "Viridia", "Greenill", "Skyly", "Bluefull", "Purplenum",
  "Pinkal", "Redria", "Oran", "Yellowboze", "Whitill",
] as const;
export type SectionId = (typeof SECTION_IDS)[number];

/**
 * Item-usability attribute bits (newserv `ItemParameterTable.hh`,
 * `Weapon::usability_flags`). An item is equippable by a class only if ALL of
 * the class's attribute bits are set in the item's `usableBy` mask.
 */
export const EQUIP_ATTR = {
  hunter: 0x01,
  ranger: 0x02,
  force: 0x04,
  human: 0x08,
  android: 0x10,
  newman: 0x20,
  male: 0x40,
  female: 0x80,
} as const;

/**
 * Animation rig for attack frame data (attack-frame-data spec). PSO ships six
 * distinct movesets: four classes animate uniquely; everyone else shares the
 * male or female rig by gender.
 */
export type Rig = "male" | "female" | "hucaseal" | "ramarl" | "fomar" | "fomarl";

const RIG_OVERRIDES: Record<string, Rig> = {
  hucaseal: "hucaseal",
  ramarl: "ramarl",
  fomar: "fomar",
  fomarl: "fomarl",
};

export function rigForClass(classId: string): Rig {
  const override = RIG_OVERRIDES[classId];
  if (override) return override;
  const mask = CLASS_EQUIP_MASK[classId];
  if (mask === undefined) throw new Error(`unknown class ${classId}`);
  return mask & EQUIP_ATTR.female ? "female" : "male";
}

/** Each class's full attribute set (role | race | gender) as an EQUIP_ATTR mask. */
export const CLASS_EQUIP_MASK: Record<string, number> = {
  humar: EQUIP_ATTR.hunter | EQUIP_ATTR.human | EQUIP_ATTR.male,
  hunewearl: EQUIP_ATTR.hunter | EQUIP_ATTR.newman | EQUIP_ATTR.female,
  hucast: EQUIP_ATTR.hunter | EQUIP_ATTR.android | EQUIP_ATTR.male,
  hucaseal: EQUIP_ATTR.hunter | EQUIP_ATTR.android | EQUIP_ATTR.female,
  ramar: EQUIP_ATTR.ranger | EQUIP_ATTR.human | EQUIP_ATTR.male,
  ramarl: EQUIP_ATTR.ranger | EQUIP_ATTR.human | EQUIP_ATTR.female,
  racast: EQUIP_ATTR.ranger | EQUIP_ATTR.android | EQUIP_ATTR.male,
  racaseal: EQUIP_ATTR.ranger | EQUIP_ATTR.android | EQUIP_ATTR.female,
  fomar: EQUIP_ATTR.force | EQUIP_ATTR.human | EQUIP_ATTR.male,
  fomarl: EQUIP_ATTR.force | EQUIP_ATTR.human | EQUIP_ATTR.female,
  fonewm: EQUIP_ATTR.force | EQUIP_ATTR.newman | EQUIP_ATTR.male,
  fonewearl: EQUIP_ATTR.force | EQUIP_ATTR.newman | EQUIP_ATTR.female,
};

